WebLink.url:
{!REQUIRESCRIPT("/soap/ajax/33.0/connection.js")} 
{!REQUIRESCRIPT("/soap/ajax/33.0/apex.js")} 

try{

var sheet = sforce.connection.query("Select id,IP_Status__c from IP_PayProfile__c where id='{!IP_PayProfile__c.Id}'"); 

records = sheet.getArray("records"); 
var paystatus = records[0].IP_Status__c; 

if(paystatus == 'Active')
{

var x = confirm('The candidate Pay Profile is active. Continue with the reinstate process will lapse all related certifications. Do you want to continue?');

if(x==true)
{
var result = sforce.apex.execute("reinstatebutton","updatedata",{payid:"{!IP_PayProfile__c.Id}"}); 
alert(result); 
window.location.reload(); 
}
else
{
window.location.reload(); 
}

}
else
{
var result = sforce.apex.execute("reinstatebutton","updatedata",{payid:"{!IP_PayProfile__c.Id}"}); 
alert(result); 
window.location.reload(); 
}
}
catch(e){ 
alert( 
"An unexpected Error has Occurred. Error: " + 
e 
); 
}
